import logging
import json
import os
import uuid
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import DefaultAzureCredential
import azure.functions as func

# --- Configuration (Load from Environment Variables) ---
COSMOS_DB_ENDPOINT = os.environ.get("COSMOS_DB_ENDPOINT")
COSMOS_DB_DATABASE_NAME = os.environ.get("COSMOS_DB_DATABASE_NAME")
COSMOS_DB_CONTAINER_NAME = os.environ.get("COSMOS_DB_CONTAINER_NAME")
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT")

# --- Initialize Azure SDK Clients using Managed Identity ---
credential = DefaultAzureCredential()

# Cosmos DB Client
cosmos_client = CosmosClient(COSMOS_DB_ENDPOINT, credential=credential)
cosmos_database = cosmos_client.get_database_client(COSMOS_DB_DATABASE_NAME)
cosmos_container = cosmos_database.get_container_client(COSMOS_DB_CONTAINER_NAME)

# Event Grid Publisher Client
event_grid_client = EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential)

# --- Azure Function Entry Point ---
app = func.FunctionApp()

@app.blob_trigger(arg_name="inputblob", path="input-files/{name}",
                  connection="AzureWebJobsStorage") # "AzureWebJobsStorage" connection string is implicitly managed for Managed Identity
def ProcessBlobFunction(inputblob: func.InputStream):
    logging.info(f"Python blob trigger function processed blob "
                 f"Name: {inputblob.name} "
                 f"Blob Size: {inputblob.length} Bytes")

    try:
        # --- 1. Read Blob Content ---
        blob_content = inputblob.read().decode('utf-8')
        logging.info(f"Successfully read blob '{inputblob.name}'. Content snippet: {blob_content[:100]}...")

        # --- 2. Process Content (Example: Simple parsing) ---
        # For this MVP, we'll just store the content and some metadata
        processing_result = {
            "id": str(uuid.uuid4()),
            "blobName": inputblob.name,
            "blobUri": inputblob.uri,
            "blobSize": inputblob.length,
            "processedTimestamp": f"{func.get_utc_timestamp()}",
            "contentPreview": blob_content[:200], # Store a snippet
            "fullContentHash": hash(blob_content) # Example of a simple derived value
        }
        logging.info(f"Processed blob '{inputblob.name}'. Result ID: {processing_result['id']}")

        # --- 3. Write Result to Cosmos DB ---
        cosmos_container.create_item(body=processing_result)
        logging.info(f"Successfully wrote processing result for '{inputblob.name}' to Cosmos DB. Item ID: {processing_result['id']}")

        # --- 4. Send Notification via Event Grid ---
        event_data = {
            "id": str(uuid.uuid4()),
            "subject": f"/blob/{inputblob.name}/processed",
            "eventType": "BlobProcessed",
            "dataVersion": "1.0",
            "data": {
                "blobUri": inputblob.uri,
                "blobName": inputblob.name,
                "processedItemId": processing_result["id"],
                "status": "Success",
                "timestamp": f"{func.get_utc_timestamp()}"
            }
        }
        
        event_grid_client.send(
            [
                EventGridEvent(
                    subject=event_data["subject"],
                    data=event_data["data"],
                    event_type=event_data["eventType"],
                    data_version=event_data["dataVersion"]
                )
            ]
        )
        logging.info(f"Successfully sent Event Grid notification for '{inputblob.name}'. Event ID: {event_data['id']}")

    except Exception as e:
        logging.error(f"Error processing blob '{inputblob.name}': {e}")
        # Optionally send a failure notification
        error_event_data = {
            "id": str(uuid.uuid4()),
            "subject": f"/blob/{inputblob.name}/processingFailed",
            "eventType": "BlobProcessingFailed",
            "dataVersion": "1.0",
            "data": {
                "blobUri": inputblob.uri,
                "blobName": inputblob.name,
                "error": str(e),
                "status": "Failed",
                "timestamp": f"{func.get_utc_timestamp()}"
            }
        }
        event_grid_client.send(
            [
                EventGridEvent(
                    subject=error_event_data["subject"],
                    data=error_event_data["data"],
                    event_type=error_event_data["eventType"],
                    data_version=error_event_data["dataVersion"]
                )
            ]
        )
        logging.info(f"Sent Event Grid 'Failed' notification for '{inputblob.name}'. Event ID: {error_event_data['id']}")